changeSet.sql:
CREATE TABLE IF NOT EXISTS document_column (
    id BIGSERIAL PRIMARY KEY,
    name VARCHAR(128) NOT NULL UNIQUE,
    source VARCHAR(32) NOT NULL DEFAULT 'SYSTEM',
    created_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP
);

ALTER TABLE knowledge_document
    ADD COLUMN IF NOT EXISTS column_id BIGINT;

ALTER TABLE document_review_request
    ADD COLUMN IF NOT EXISTS selected_column_name VARCHAR(128);

CREATE INDEX IF NOT EXISTS idx_knowledge_document_column_id
    ON knowledge_document(column_id);

ALTER TABLE knowledge_document
    ADD CONSTRAINT fk_knowledge_document_column
    FOREIGN KEY (column_id) REFERENCES document_column(id);
